// Evolution API real format
const body = $input.first().json.body || $input.first().json;
const eventRaw = body.event || body.type || '';
const event = eventRaw.toLowerCase().replace(/_/g, '.');
const messageEvents = ['messages.upsert', 'messages.update'];
if (!messageEvents.includes(event)) return [];
const data = body.data || {};
const message = data.message || {};
const key = data.key || {};
if (event === 'messages.update' && !message.conversation && !message.extendedTextMessage) return [];
const tipo = message.audioMessage ? 'audio' : message.imageMessage ? 'image' : message.documentMessage ? 'document' : 'text';
const conteudo = message.conversation || message.extendedTextMessage?.text || null;
return [{ json: { event, tipo, from_me: key.fromMe || false, session_id: body.instance || $env.ML_EVOLUTION_INSTANCE, remote_jid: key.remoteJid, push_name: data.pushName || null, message_id: key.id || null, conteudo_raw: conteudo, audio_url: message.audioMessage?.url || null, duracao_audio: message.audioMessage?.seconds || null, metadados: body } }];

const payload = $("Normalizar Payload").first().json;
const lookup = $input.first().json;
const area = lookup.area || 'comercial';
const projeto_id = lookup.projeto_id || null;
const numero_tipo = lookup.numero_tipo || 'mono';
const agente_default_id = lookup.agente_default_id || null;
const numero_id = lookup.numero_id || null;
return [{ json: { ...payload, area, projeto_id, numero_tipo, agente_default_id, numero_id } }];

const payload = $("Enriquecer com Setor").first().json;
const whisper = $input.first().json;
return [{ json: { mensagem: { area: payload.area, fonte: 'whatsapp', session_id: payload.session_id, remote_jid: payload.remote_jid, message_id: payload.message_id, tipo: 'audio', conteudo_raw: whisper.text, audio_url: payload.audio_url, duracao_audio: payload.duracao_audio, status: 'processada', metadados: payload.metadados }, transcricao: { texto: whisper.text, idioma: whisper.language || 'pt', confianca: whisper.segments?.[0]?.avg_logprob ? Math.exp(whisper.segments[0].avg_logprob) : null, provider: 'groq-whisper' } } }];

const error = $input.first().json;
console.error('[ML-CAPTURA] Erro no pipeline:', JSON.stringify({ timestamp: new Date().toISOString(), error: error.message || 'Erro desconhecido', node: $runIndex }));
return [{ json: { status: 'error_logged', error: error.message } }];

const dados = $("Enriquecer com Setor").first().json;
const tipo = dados.numero_tipo || 'mono';
let agente_humano_id = null;
if (tipo === 'mono') {
  agente_humano_id = dados.agente_default_id || null;
} else {
  try {
    const r = $("Lookup Agente Multi").first().json;
    agente_humano_id = r.agente_multi_id || null;
  } catch (e) {
    agente_humano_id = null;
  }
}
return [{ json: { ...dados, agente_humano_id } }];

